// UploadVideo registers a new video in the DB and enqueues it for processing.
func (r *mutationResolver) UploadVideo(ctx context.Context, title string, s3Key string) (*model.Video, error) {
	userID := userIDFromCtx(ctx)

	// Enforce per-user limit of 3 non-demo videos.
	var count int
	if err := r.DB.Pool.QueryRow(ctx,
		`SELECT COUNT(*) FROM videos WHERE user_id=$1 AND is_demo=FALSE`, userID,
	).Scan(&count); err == nil && count >= 3 {
		return nil, fmt.Errorf("upload limit reached: delete a video before uploading a new one")
	}

	var id int
	if err := r.DB.Pool.QueryRow(ctx,
		`INSERT INTO videos (title, s3_key, status, user_id) VALUES ($1, $2, 'queued', $3) RETURNING id`,
		title, s3Key, userID,
	).Scan(&id); err != nil {
		return nil, fmt.Errorf("insert video: %w", err)
	}

	return dbQueryVideo(ctx, r.DB, strconv.Itoa(id))
}

// DeleteVideo removes a video and its cascading chat data (ownership enforced).
func (r *mutationResolver) DeleteVideo(ctx context.Context, id string) (bool, error) {
	userID := userIDFromCtx(ctx)
	tag, err := r.DB.Pool.Exec(ctx,
		`DELETE FROM videos WHERE id=$1 AND user_id=$2 AND is_demo=FALSE`,
		id, userID,
	)
	if err != nil {
		return false, fmt.Errorf("delete video: %w", err)
	}
	return tag.RowsAffected() > 0, nil
}

