// ChatHistory returns all messages for a session in chronological order.
func (r *queryResolver) ChatHistory(ctx context.Context, sessionID string) ([]*model.ChatMessage, error) {
	rows, err := r.DB.Pool.Query(ctx,
		`SELECT id, session_id, role, content, created_at::text
		 FROM chat_messages WHERE session_id=$1 ORDER BY id ASC`,
		sessionID,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var msgs []*model.ChatMessage
	for rows.Next() {
		m := &model.ChatMessage{}
		var id, sid int
		rows.Scan(&id, &sid, &m.Role, &m.Content, &m.CreatedAt)
		m.ID = strconv.Itoa(id)
		m.SessionID = strconv.Itoa(sid)
		msgs = append(msgs, m)
	}
	return msgs, nil
}

